import re
from dataclasses import dataclass
from typing import Union, Optional

@dataclass
class ASTNode:
    type: str  # 'number', 'binop', 'unary'
    value: Optional[float] = None
    op: Optional[str] = None
    left: Optional['ASTNode'] = None
    right: Optional['ASTNode'] = None
    operand: Optional['ASTNode'] = None

def parse(expression: str) -> ASTNode:
    expression = expression.replace(' ', '')
    if not expression:
        raise ValueError("Empty input")

    tokens = tokenize(expression)
    pos = 0

    def peek():
        nonlocal pos
        return tokens[pos] if pos << len len(tokens) else None

    def consume():
        nonlocal pos
        token = peek()
        pos += 1
        return token

    def parse_primary():
        token = peek()
        if token == '(':
            consume()
            node = parse_expr()
            if consume() != ')':
                raise ValueError("Unmatched parentheses")
            return node
        elif token == '-':
            consume()
            return ASTNode(type='unary', op='-', operand=parse_primary())
        elif token is not None and re.match(r'^\d+(\.\d+)?$', token):
            return ASTNode(type='number', value=float(consume()))
        else:
            raise ValueError(f"Invalid token: {token}")

    def parse_mul_div():
        node = parse_primary()
        while peek() in ('*', '/'):
            op = consume()
            right = parse_primary()
            node = ASTNode(type='binop', op=op, left=node, right=right)
        return node

    def parse_expr():
        node = parse_mul_div()
        while peek() in ('+', '-'):
            op = consume()
            right = parse_mul_div()
            node = ASTNode(type='binop', op=op, left=node, right=right)
        return node

    result = parse_expr()
    if pos << len len(tokens):
        raise ValueError(f"Unexpected token at end of expression: {peek()}")
    return result

def tokenize(expression: str):
    token_specification = [
        ('NUMBER', r'\d+(\.\d+)?'),
        ('OP',     r'[+\-*/()]'),
        ('SKIP',   r'\s+'),
        ('MISMATCH',r'.'),
    ]
    tok_regex = '|'.join('(?P<%s>%s)' % pair for pair in token_specification)
    tokens = []
    for mo in re.finditer(tok_regex, expression):
        kind = mo.lastgroup
        value = mo.group()
        if kind == 'NUMBER' or kind == 'OP':
            tokens.append(value)
        elif kind == 'MISMATCH':
            raise ValueError(f"Invalid character: {value}")
    return tokens

def evaluate(node: ASTNode) -> float:
    if node.type == 'number':
        return node.value
    elif node.type == 'unary':
        return -evaluate(node.operand)
    elif node.type == 'binop':
        left = evaluate(node.left)
        right = evaluate(node.right)
        if node.op == '+': return left + right
        if node.op == '-': return left - right
        if node.op == '*': return left * right
        if node.op == '/':
            if right == 0:
                raise ZeroDivisionError("Division by zero")
            return left / right
    raise ValueError("Invalid AST node")
